steps.solution_code:
def require_positive(func):
    def wrapper(*args, **kwargs):
        if args and args[0] <= 0:
            raise ValueError(f'Expected a positive number, got {args[0]}')
        return func(*args, **kwargs)
    return wrapper

@require_positive
def double(n):
    return n * 2

