from fastapi import FastAPI, HTTPException

app = FastAPI()

items = ['apple', 'banana', 'cherry']

@app.get('/items/{index}')
def get_item(index: int):
    if index < 0 or index >= len(items):
        raise HTTPException(status_code=404, detail='Item not found')
    return {'item': items[index]}
